changeSet.sql:
-- Insertar si no existe INSERT INTO usuario (username, password, nombre, rol, cliente_id) SELECT 'usuario1', 'user123', 'Usuario Demo', 'USUARIO', (SELECT id FROM cliente ORDER BY id LIMIT 1) WHERE NOT EXISTS (SELECT 1 FROM usuario WHERE username = 'usuario1');
-- Reparar cliente_id si es NULL UPDATE usuario SET cliente_id = (SELECT id FROM cliente ORDER BY id LIMIT 1) WHERE username = 'usuario1' AND cliente_id IS NULL AND EXISTS (SELECT 1 FROM cliente LIMIT 1);
-- Garantizar que admin exista INSERT INTO usuario (username, password, nombre, rol) SELECT 'admin', 'admin123', 'Administrador', 'ADMIN' WHERE NOT EXISTS (SELECT 1 FROM usuario WHERE username = 'admin');
